/**
 * Build a full payload and send it through the appropriate adapter.
 * Dispatches are serialized per-user to guarantee notification ordering.
 */
private dispatch(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  userId?: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
}): Promise<void> {
  const queueKey = params.userId ?? params.recipient;
  const previous = this.dispatchQueues.get(queueKey) ?? Promise.resolve();
  const next = previous.then(() => this.doDispatch(params));
  this.dispatchQueues.set(queueKey, next.catch(() => {}));
  return next;
}

/**
 * Internal dispatch — actually sends the notification through the adapter.
 */
private async doDispatch(params: {
  type: NotificationType;
  channel: NotificationChannel;
  recipient: string;
  userId?: string;
  subject: string;
  body: string;
  metadata?: Record<string, unknown>;
}): Promise<void> {
  // Check user preferences before sending (all channels)
  if (params.userId && this.preferencesService) {
    if (!this.preferencesService.shouldSendToChannel(params.userId, params.channel, params.type)) {
      this.logger.info(`Notification ${params.type} on ${params.channel} suppressed for user ${params.userId} (preference)`);
      return;
    }
  }

  const payload: NotificationPayload = {
    id: generateNotificationId(),
    type: params.type,
    channel: params.channel,
    recipient: params.recipient,
    subject: params.subject,
    body: params.body,
    metadata: params.metadata,
    createdAt: new Date(),
  };

  const adapter = this.adapters.get(params.channel);
  if (!adapter) {
    this.logger.warn(`No adapter registered for channel: ${params.channel}`);
    const failResult = {
      success: false as const,
      channel: params.channel,
      error: `No adapter registered for channel: ${params.channel}`,
      deliveredAt: new Date(),
    };
    this.records.push({ payload, result: failResult });
    this.historyService?.logNotification(payload, failResult, params.userId);
    return;
  }

  const result = await adapter.send(payload);
  this.records.push({ payload, result });
  this.historyService?.logNotification(payload, result, params.userId);
  this.logger.info(`Notification ${payload.id} dispatched via ${params.channel}: ${result.success ? 'success' : 'failed'}`);
}

